INSERT INTO `feedback`
 (`id`,`title`,`content`,`anon_name`,`emoji`,`color`,`like_count`,`create_by`,`create_time`,`update_time`) VALUES
 (97201,'样机申请流程太长了','从提交申请到拿到样机要走五六个审批节点，客户都等急了，能不能给热门型号开个快速通道？','匿名的打工人','😤','#eb2f96',128,9001,'2026-07-15 10:20:00','2026-07-15 10:20:00'),
 (97202,'规格书版本太乱','同一个型号官网、内网、销售包里的规格书版本都不一样，报参数经常报错，求统一出口。','被参数折磨的销售','🤯','#fa8c16',96,9001,'2026-07-14 16:40:00','2026-07-14 16:40:00'),
 (97203,'报价系统半夜维护','偏偏在我赶客户方案的时候维护，能不能提前发个通知或者错峰一下。','熬夜冠军','😩','#722ed1',74,9001,'2026-07-14 09:15:00','2026-07-14 09:15:00'),
 (97204,'希望多点竞品对比资料','客户天天拿友商参数压价，我们自己的竞品对比表更新太慢了，跟不上节奏。','前线炮火','😮‍💨','#1890ff',61,9001,'2026-07-13 14:05:00','2026-07-13 14:05:00'),
 (97205,'会议纪要任务经常漏派','开完会任务没人录进系统，过两天就忘了，建议会议结束直接在平台上派任务。','记性不好的我','🫠','#13c2c2',53,9001,'2026-07-12 18:30:00','2026-07-12 18:30:00'),
 (97206,'移动端体验有待加强','在客户现场只能掏手机查方案，可惜手机上表格全挤在一起，基本没法看。','出差达人','📱','#faad14',47,9001,'2026-07-12 08:50:00','2026-07-12 08:50:00'),
 (97207,'订阅通知太多了','一天几十条推送，真正重要的反而被淹没，希望能按重要程度分级。','被通知刷屏的人','🙄','#2f54eb',42,9001,'2026-07-11 11:25:00','2026-07-11 11:25:00'),
 (97208,'分类标签不够细','找车载相关方案的时候标签太笼统，翻好几页才找到想要的，建议加二级标签。','找方案找到头秃','😅','#52c41a',38,9001,'2026-07-10 15:40:00','2026-07-10 15:40:00'),
 (97209,'希望有方案模板库','每次写客户方案都从零开始，要是有标准模板能省一半时间。','重复劳动受害者','🥲','#eb2f96',35,9001,'2026-07-09 09:10:00','2026-07-09 09:10:00'),
 (97210,'搜索结果不太准','搜型号经常搜不到，反而搜到一堆不相关的帖子，搜索能不能优化下权重。','搜索困难户','👀','#fa8c16',29,9001,'2026-07-08 13:55:00','2026-07-08 13:55:00'),
 (97211,'点赞收藏找不到入口','收藏过的方案后来想再看，翻半天找不到我的收藏在哪，个人中心能不能显眼点。','路痴用户','🧭','#722ed1',24,9001,'2026-07-07 17:20:00','2026-07-07 17:20:00'),
 (97212,'夸一句：情报中心很好用','竞品动态更新挺及时，上次靠一条价格变动情报稳住了客户，给运营点个赞！','真香现场','🎉','#52c41a',88,9001,'2026-07-06 10:00:00','2026-07-06 10:00:00'),
 (97213,'附件预览老是失败','PPT 附件在线预览经常转圈加载不出来，只能下载，能不能修一下预览。','转圈圈观察员','🔄','#13c2c2',19,9001,'2026-07-05 14:30:00','2026-07-05 14:30:00');
INSERT INTO `competitor_intel`
 (`id`,`brand`,`product`,`intel_type`,`title`,`summary`,`source`,`submitter_id`,`submitter_name`,`overview`,`analysis`,`impact`,`specs`,`like_count`,`collect_count`,`view_count`,`create_by`,`create_time`,`update_time`) VALUES
 (97301,'Telit','FN990','new_product','Telit 发布 FN990 系列 5G Sub-6/毫米波模组','FN990 支持 5G NR Sub-6GHz 与毫米波，面向 FWA 与工业路由，主打高吞吐与低时延。','Telit 官网新闻',NULL,'张伟','Telit 正式发布 FN990 系列 5G 模组，基于高通 SDX62 平台，同时支持 Sub-6GHz 与毫米波频段，覆盖全球主流 5G 频段。产品面向 FWA、工业路由与高端 CPE 场景，主打高吞吐与低时延，是 Telit 在 5G 旗舰模组上对标移远 RG500Q 系列的最新布局。','FN990 同时覆盖 Sub-6 与毫米波，是目前少数在单一产品线打通两大频段的竞品模组。若其毫米波性能与散热控制达到宣传水平，将在北美 FWA 市场对我司形成直接压力。建议尽快获取样片，重点对比毫米波场景下的吞吐稳定性与功耗表现。','FN990 主要冲击中高端 5G 市场。建议产品线梳理 RG500Q 后续毫米波路线图，销售侧在 FWA 项目中提前准备差异化材料，突出本地 FAE 支持与供货周期优势。','[{"label":"平台","value":"高通 SDX62"},{"label":"5G 模式","value":"SA / NSA 双模"},{"label":"频段","value":"Sub-6GHz + 毫米波"},{"label":"下行速率","value":"最高 4.4 Gbps"},{"label":"封装","value":"M.2 / LGA"},{"label":"目标市场","value":"FWA、工业路由、CPE"}]',42,18,326,9001,'2026-07-11 09:30:00','2026-07-11 09:30:00'),
 (97302,'广和通','FM650','price_change','广和通 FM650 5G 模组渠道报价下调约 12%','受供应链成本回落影响，广和通对 FM650 渠道价进行下调，进一步压缩中端 5G 模组价格空间。','渠道商反馈',NULL,'李娜','据多家渠道商反馈，广和通近期对其中端 5G 模组 FM650 渠道出货价下调约 12%，此举被认为是应对上游成本回落、争夺中端 5G 项目份额的主动策略，重点针对价格敏感的行业客户。','FM650 与我司中端 5G 模组定位重叠，降价后在渠道招标中的价格竞争力提升。对于以单价为核心决策因素的中小客户，价差可能直接影响选型结果。需关注其实际出货价与报价的差距，避免被渠道话术带偏。','短期内中端 5G 项目报价压力上升。建议销售团队准备 TCO 对比材料，突出功耗、供货稳定性与技术支持等非价格因素，并对重点客户提前做好客情维护。','[{"label":"降价幅度","value":"约 12%"},{"label":"影响产品","value":"FM650 全系列"},{"label":"覆盖市场","value":"中国大陆渠道"},{"label":"目标场景","value":"工业网关、行业终端"}]',28,12,214,9001,'2026-07-10 14:20:00','2026-07-10 14:20:00'),
 (97303,'Sierra Wireless','EM919x','customer_case','Sierra EM919x 在北美工业路由客户批量导入','某北美工业路由厂商采用 EM919x 完成量产，主打运营商认证齐全与长期供货。','行业展会交流',NULL,'王强','Sierra Wireless 的 EM919x 5G 模组在某北美工业路由厂商完成批量导入并进入量产，该客户看重 Sierra 齐全的北美运营商认证与长期供货承诺。这是 Sierra 在北美工业市场巩固存量客户的典型案例。','北美工业路由市场对运营商认证与供货连续性极为敏感，Sierra 在此具备本土优势。该案例说明在部分海外存量客户处，认证齐全度与供货承诺可能比价格更关键，我司需在这两点上补齐说服材料。','对北美工业客户拓展形成一定阻力。建议加快重点北美运营商认证进度，并整理长期供货保障方案作为标准销售话术。','[{"label":"中标产品","value":"EM919x 5G 模组"},{"label":"应用场景","value":"工业路由 / 网关"},{"label":"客户区域","value":"北美"},{"label":"关键因素","value":"运营商认证、长期供货"}]',35,15,268,9001,'2026-07-09 11:00:00','2026-07-09 11:00:00'),
 (97304,'u-blox','LARA-R6','new_product','u-blox 推出 LARA-R6 全球 LTE Cat.1 模组','LARA-R6 单一硬件覆盖全球频段，主打车规与工业市场，强调长生命周期供货。','u-blox 产品公告',NULL,'赵敏','u-blox 发布 LARA-R6 全球 LTE Cat.1 模组，以单一硬件覆盖全球频段为卖点，面向车规与工业市场，强调超长生命周期供货，契合欧洲客户对长期供货与合规的偏好。','LARA-R6 的全球单一硬件方案降低了客户的多区域备货复杂度，对跨国部署的工业客户有吸引力。u-blox 在欧洲车规与工业市场品牌力较强，需关注其对我司 Cat.1 出海产品的挤压。','对 Cat.1 出海项目形成竞争。建议突出我司 Cat.1 的成本优势与丰富量产案例，并针对跨区域客户提供全球频段选型指导。','[{"label":"制式","value":"LTE Cat.1"},{"label":"频段","value":"全球频段单一硬件"},{"label":"目标市场","value":"车规、工业"},{"label":"卖点","value":"长生命周期供货"}]',21,9,176,9001,'2026-07-08 10:15:00','2026-07-08 10:15:00'),
 (97305,'Thales','Cinterion MV32','other','Thales MV32 强化 eSIM 与安全能力','MV32 集成 IoT SAFE 与 eSIM，面向对安全合规要求高的能源与支付场景。','厂商白皮书',NULL,'陈涛','Thales 更新其 Cinterion MV32 模组，集成 IoT SAFE 与 eSIM 能力，面向能源、支付等对安全合规要求较高的场景，延续 Thales 在安全领域的差异化定位。','Thales 借助其在安全与身份认证领域的积累，将安全能力做成模组卖点，在高合规门槛场景具备一定壁垒。对我司而言，安全启动、eSIM 与远程管理能力将逐步从加分项变为刚需。','在高安全场景项目中可能面临差异化竞争。建议梳理我司模组的安全特性清单，并在能源、支付类项目中形成标准化的安全能力说明。','[{"label":"安全能力","value":"IoT SAFE + eSIM"},{"label":"目标场景","value":"能源、支付"},{"label":"差异化","value":"安全合规"}]',17,7,142,9001,'2026-07-07 16:40:00','2026-07-07 16:40:00'),
 (97306,'Telit','ME910G1','price_change','Telit ME910G1 LTE-M/NB 模组年度框架价上浮','受特定料件涨价影响，Telit 对 ME910G1 框架价小幅上浮，NB 市场竞争态势变化。','客户采购通报',NULL,'刘洋','据客户采购通报，Telit 因特定料件涨价对 ME910G1 LTE-M/NB 模组的年度框架价小幅上浮，NB-IoT 市场的价格竞争态势出现变化，为我司同级产品创造了一定窗口。','竞品被动涨价，是我司 NB 产品争取价格敏感客户的机会窗口。建议销售团队关注使用 ME910G1 的存量客户，主动接触并提供有竞争力的替换方案。','NB 市场出现拓展窗口。建议快速锁定竞品涨价影响的客户名单，准备替换选型与迁移支持材料。','[{"label":"制式","value":"LTE-M / NB-IoT"},{"label":"价格变化","value":"框架价小幅上浮"},{"label":"诱因","value":"料件涨价"}]',23,10,158,9001,'2026-07-06 09:50:00','2026-07-06 09:50:00'),
 (97307,'广和通','SC138','customer_case','广和通 SC138 智能座舱模组拿下车厂定点','广和通 SC138 在某自主品牌车厂智能座舱项目获得定点，涉及多车型平台。','汽车行业媒体',NULL,'周杰','广和通宣布其智能座舱模组 SC138 在某自主品牌车厂的座舱项目获得定点，覆盖多个车型平台，预计带来可观的长期出货，是广和通在车载座舱赛道的重要突破。','座舱是车载高价值赛道，多车型平台定点意味着长期绑定与规模出货。丢失该类项目不仅是单次订单损失，更是错失在客户平台上建立长期关系的入口，需重点复盘。','车载座舱竞争加剧。建议复盘该客户的技术交流过程，加强对现有车厂客户的定期沟通与联合创新，防止进一步流失。','[{"label":"中标产品","value":"SC138 座舱模组"},{"label":"应用场景","value":"智能座舱"},{"label":"客户行业","value":"自主品牌车厂"},{"label":"覆盖范围","value":"多车型平台"}]',31,14,242,9001,'2026-07-05 13:10:00','2026-07-05 13:10:00'),
 (97308,'Sierra Wireless','RC7620','new_product','Sierra RC7620 紧凑型 LTE 模组面向可穿戴','RC7620 主打小尺寸与低功耗，面向可穿戴与资产追踪场景，强调全球运营商认证。','厂商新闻稿',NULL,'郑浩','Sierra Wireless 推出紧凑型 LTE 模组 RC7620，主打小尺寸与低功耗，面向可穿戴与资产追踪场景，并强调其齐全的全球运营商认证，便于客户快速出海。','可穿戴与资产追踪对尺寸、功耗和认证齐全度要求高。Sierra 凭借运营商认证优势在海外市场具备快速落地能力，我司需在小尺寸低功耗产品线上保持竞争力。','对可穿戴/追踪类出海项目形成竞争。建议突出我司对应产品的功耗与成本优势，并加快重点区域运营商认证。','[{"label":"制式","value":"LTE"},{"label":"特点","value":"小尺寸、低功耗"},{"label":"目标场景","value":"可穿戴、资产追踪"},{"label":"卖点","value":"全球运营商认证"}]',19,8,151,9001,'2026-07-04 08:20:00','2026-07-04 08:20:00'),
 (97309,'Sequans','Monarch 2 GM02S','new_product','Sequans 发布 Monarch 2 GM02S 超低功耗 LTE-M/NB 模组','GM02S 集成 eSIM 与安全套件，主打极致低功耗与小尺寸，面向资产追踪与表计。','Sequans 官网新闻',NULL,'许晴','Sequans 正式推出第二代 Monarch 2 平台的 GM02S 模组，集成 eSIM 与安全启动套件，主打极致低功耗（PSM/eDRX 深度优化）与小尺寸封装，面向资产追踪、智能表计与可穿戴等中低速物联网场景，延续 Sequans 在低功耗 LTE-M 领域的技术标签。','GM02S 在待机功耗与安全集成上均有提升，对功耗敏感的电池供电场景吸引力较强。Sequans 以低功耗为核心差异点，与我司 BC660K 等 NB 产品在表计与追踪市场存在直接重叠，需关注其实测续航数据。','对低功耗 NB/LTE-M 出海项目形成竞争。建议整理我司对应产品的功耗实测对比与量产案例，突出成本与本地支持优势。','[{"label":"制式","value":"LTE-M / NB-IoT"},{"label":"平台","value":"Monarch 2"},{"label":"特点","value":"超低功耗、集成 eSIM"},{"label":"封装","value":"小尺寸 LGA"},{"label":"目标场景","value":"资产追踪、表计、可穿戴"}]',22,11,183,9001,'2026-01-14 10:20:00','2026-01-14 10:20:00'),
 (97310,'Nordic','nRF9161','new_product','Nordic nRF9161 集成 LTE-M/NB 与 DECT NR+ 免授权频谱','nRF9161 在蜂窝之外新增 DECT NR+ 支持，面向工业无线与私有组网场景。','Nordic 产品公告',NULL,'范文博','Nordic 发布 nRF9161 SiP，在 LTE-M/NB-IoT 蜂窝能力之外新增 DECT NR+ 免授权频谱支持，主打工业无线传感与私有组网，配合其成熟的 nRF Connect SDK 生态，吸引偏好一体化软硬件方案的开发者。','DECT NR+ 为免授权频谱下的确定性无线组网提供新选项，Nordic 借助开发者生态在原型与中小批量项目上转化能力强。该方向短期规模有限，但需跟踪其在工业传感市场的渗透节奏。','对工业传感与私有组网项目形成潜在竞争。建议评估 DECT NR+ 场景需求，梳理我司蜂窝+短距组合方案的应对材料。','[{"label":"制式","value":"LTE-M / NB-IoT + DECT NR+"},{"label":"形态","value":"SiP 系统级封装"},{"label":"生态","value":"nRF Connect SDK"},{"label":"目标场景","value":"工业无线、私有组网"},{"label":"差异化","value":"免授权频谱组网"}]',18,9,164,9001,'2026-02-09 09:40:00','2026-02-09 09:40:00'),
 (97311,'u-blox','SARA-R10','customer_case','u-blox SARA-R10 在欧洲智能表计项目批量导入','某欧洲水务表计厂商采用 SARA-R10 完成量产，看重超长生命周期与本地合规支持。','行业展会交流',NULL,'何俊','u-blox 的 SARA-R10 LTE-M/NB 模组在某欧洲水务表计厂商完成批量导入并进入量产，客户看重 u-blox 的超长生命周期供货承诺与本地合规、认证支持，是 u-blox 在欧洲表计存量市场的典型案例。','欧洲表计市场对供货生命周期与合规认证极为敏感，u-blox 本土品牌力与长供货承诺构成壁垒。该案例说明在部分欧洲存量客户处，长期供货与合规支持可能比价格更关键，需在这两点补齐说服材料。','对欧洲表计客户拓展形成一定阻力。建议突出我司 NB/LTE-M 表计产品的量产规模与成本优势，并加快欧洲重点区域合规认证。','[{"label":"中标产品","value":"SARA-R10 LTE-M/NB 模组"},{"label":"应用场景","value":"智能水务表计"},{"label":"客户区域","value":"欧洲"},{"label":"关键因素","value":"长生命周期、本地合规"}]',26,12,205,9001,'2026-03-18 14:05:00','2026-03-18 14:05:00'),
 (97312,'Telit','LE910C4','price_change','Telit LE910C4 Cat.4 模组渠道报价上浮约 8%','受料件与汇率影响，Telit 对 LE910C4 渠道价上浮，Cat.4 中端市场出现窗口。','渠道商反馈',NULL,'邓超','据多家渠道商反馈，Telit 因关键料件涨价与汇率波动，对其 Cat.4 主力模组 LE910C4 渠道出货价上浮约 8%，中端 Cat.4 市场的价格竞争态势出现变化，为我司 EC200A 等同级产品创造了一定替换窗口。','竞品被动涨价是我司 Cat.4 产品争取价格敏感客户的机会窗口。建议关注使用 LE910C4 的存量客户，主动接触并提供有竞争力的替换方案与迁移支持。','Cat.4 中端市场出现拓展窗口。建议快速锁定受涨价影响的客户名单，准备 EC200A 替换选型与商务对比材料。','[{"label":"制式","value":"LTE Cat.4"},{"label":"价格变化","value":"渠道价上浮约 8%"},{"label":"诱因","value":"料件涨价、汇率波动"},{"label":"影响产品","value":"LE910C4 全系列"}]',25,11,172,9001,'2026-04-22 11:30:00','2026-04-22 11:30:00'),
 (97313,'Sierra Wireless','HL7810','other','Sierra HL7810 强化 IoT 安全与运营商预认证','HL7810 集成 IoT SAFE 与主流北美运营商预认证，降低客户出海认证门槛。','厂商白皮书',NULL,'曾磊','Sierra Wireless 更新其 HL7810 LTE-M/NB 模组，集成 IoT SAFE 安全能力并完成主流北美运营商预认证，主打降低客户出海时的安全合规与认证门槛，延续 Sierra 在北美市场的认证优势定位。','运营商预认证与安全集成组合，进一步降低了客户在北美落地的时间与合规成本，对急于出海的中小客户吸引力强。安全启动、IoT SAFE 等能力将逐步从加分项变为北美项目刚需。','对北美 LTE-M/NB 出海项目形成竞争。建议加快我司对应产品的北美运营商认证，并整理标准化的安全能力说明清单。','[{"label":"制式","value":"LTE-M / NB-IoT"},{"label":"安全能力","value":"IoT SAFE"},{"label":"认证","value":"北美主流运营商预认证"},{"label":"差异化","value":"出海认证门槛降低"}]',20,10,158,9001,'2026-05-16 16:10:00','2026-05-16 16:10:00'),
 (97314,'广和通','L610','customer_case','广和通 L610 Cat.1 bis 模组拿下共享出行项目','广和通 L610 在某共享两轮出行客户中标，覆盖大批量车载智能终端。','客户采购通报',NULL,'宋佳','广和通宣布其 Cat.1 bis 模组 L610 在某共享两轮出行客户的智能车锁与终端项目中标，覆盖大批量车载智能终端，预计带来规模化长期出货，是广和通在共享出行赛道巩固份额的代表案例。','共享出行是 Cat.1 bis 大规模出货的典型赛道，对单价与供货连续性极为敏感。丢失此类项目意味着规模出货与客户平台入口的双重损失，需重点复盘商务与供货策略。','Cat.1 bis 大批量市场竞争加剧。建议复盘该客户选型过程，突出我司 EC200A 系列的成本、功耗与供货稳定性优势，加强对头部出行客户的客情维护。','[{"label":"中标产品","value":"L610 Cat.1 bis 模组"},{"label":"应用场景","value":"共享出行智能车锁/终端"},{"label":"客户行业","value":"共享两轮出行"},{"label":"覆盖范围","value":"大批量终端"}]',30,13,236,9001,'2026-06-12 13:25:00','2026-06-12 13:25:00');
INSERT INTO `industry_intel`
 (`id`,`industry`,`title`,`summary`,`source`,`overview`,`analysis`,`impact`,`key_points`,`like_count`,`collect_count`,`view_count`,`create_by`,`create_time`,`update_time`) VALUES
 (97401,'trend','eRedCap 加速轻量 IoT 市场分层，2027 出货预期上调','机构预测 eRedCap 将进一步细分中低速 IoT 市场，与 Cat.1 bis 形成互补，出货预期上调。','第三方市场研究报告','第三方研究机构最新报告指出，eRedCap 作为 RedCap 的进一步轻量化演进，将加速中低速 IoT 市场的分层，与 Cat.1 bis 形成互补而非替代，2027 年出货预期被上调。报告认为运营商网络侧的成熟度是关键变量。','eRedCap 的分层意味着 5G 轻量化产品矩阵需要更细的档位划分。对我司而言，既要巩固 Cat.1 bis 基本盘，也要提前布局 eRedCap 产品与认证节奏，避免在新档位上被抢占先机。','建议产品线完善 RedCap/eRedCap 产品矩阵与认证规划，销售侧关注工业传感、表计等目标场景的早期机会。','["eRedCap 面向中低速率、低成本 5G 场景，进一步细分市场","与 Cat.1 bis 互补，短期不会形成直接替代","2027 年 eRedCap 出货预期较上一版报告上调","运营商网络支持进度是规模落地的关键变量"]',56,32,512,9001,'2026-07-11 10:00:00','2026-07-11 10:00:00'),
 (97402,'automotive','车载 5G+C-V2X 前装渗透率持续提升','多家车厂将 C-V2X 纳入中高配标配，前装通信模组需求结构向 5G 迁移。','汽车电子行业周报','行业周报显示，多家车厂将 C-V2X 纳入中高配车型标配，前装通信模组需求结构持续向 5G 迁移，5G+V2X 双模正在成为新车型的主流配置方向。','5G+V2X 双模逐步成为车载前装门槛，仅支持蜂窝的模组将难以满足新车型要求。这对具备车规与 V2X 能力的厂商是机会，也是对产品认证节奏的考验。','建议加快下一代车规模组的 V2X 支持与认证，销售侧向车厂客户同步双模趋势与选型建议，抢占标杆车型。','["多家车厂在中高配车型标配 C-V2X","前装模组需求从 4G 向 5G 结构性迁移","5G+V2X 双模成为新车型主流配置","车规认证与功能安全要求同步抬高"]',48,27,436,9001,'2026-07-10 09:15:00','2026-07-10 09:15:00'),
 (97403,'policy','多地出台智慧农业补贴，物联网终端招标增多','地方政府智慧农业专项补贴落地，土壤墒情与灌溉监测类项目招标数量明显上升。','公开招标信息汇总','多地陆续出台智慧农业专项补贴政策，带动土壤墒情、灌溉监测等物联网终端项目招标数量明显上升，NB-IoT 与 Cat.1 模组需求随之增长。','政策补贴驱动的智慧农业项目为低速物联网模组带来增量需求，且政府主导项目回款稳定。需关注各地招标节奏，提前对接集成商与终端厂商。','建议销售团队梳理智慧农业目标区域与集成商名单，准备墒情/灌溉场景的模组选型与低功耗方案材料。','["多地落地智慧农业专项补贴","墒情监测、智能灌溉类项目招标增多","NB-IoT / Cat.1 模组是主力选型","项目多为政府主导，回款相对稳定"]',33,19,298,9001,'2026-07-09 14:30:00','2026-07-09 14:30:00'),
 (97404,'energy','新型储能与充电桩通信国标推进，模组需求增长','储能与充电基础设施通信接口标准化推进，带动工业级通信模组稳定增长。','能源行业协会通讯','储能与充电基础设施的通信接口标准化持续推进，相关国标制定加速，带动工业级通信模组在能源领域的稳定增长，尤其是对可靠性与温度范围要求较高的场景。','能源基础设施对模组的可靠性与生命周期要求严苛，标准化推进将抬高合规门槛，利好具备工业级产品与认证积累的厂商。','建议突出我司工业级模组的宽温、可靠性与长供货能力，跟踪储能/充电桩国标进展并提前完成合规对齐。','["储能与充电桩通信接口标准化推进","工业级通信模组需求稳定增长","对可靠性、宽温、长供货要求高","国标落地将提升合规选型门槛"]',29,16,264,9001,'2026-07-08 11:45:00','2026-07-08 11:45:00'),
 (97405,'industrial','工业 IoT 私有 5G 专网试点扩大','制造企业私有 5G 专网试点范围扩大，对高可靠工业模组与定制化需求提升。','工业互联网联盟简报','多家制造企业扩大私有 5G 专网试点范围，从单点验证走向多产线部署，对高可靠工业模组与定制化能力的需求同步提升。','私有 5G 专网规模化落地对模组的可靠性、定制化与本地支持提出更高要求，具备工业积累与定制能力的厂商更易切入标杆项目。','建议针对头部制造客户提供专网场景定制方案与联合创新，突出本地 FAE 快速响应能力。','["制造企业私有 5G 专网试点扩大","从试点走向多产线规模部署","对高可靠、定制化模组需求提升","边缘计算与 5G 专网融合加深"]',26,13,231,9001,'2026-07-07 16:00:00','2026-07-07 16:00:00'),
 (97406,'smartcity','智慧城市感知终端集采规模扩大，LoRa/NB 并行','多地智慧城市项目扩大感知终端集采，LoRa 与 NB-IoT 技术路线并行推进。','智慧城市项目公示','多地智慧城市项目扩大感知终端集采规模，LoRa 与 NB-IoT 两条技术路线并行推进，覆盖智能路灯、环境监测、智慧停车等多类场景。','智慧城市集采规模大、场景多，LoRa 与 NB 并行意味着需要多制式产品组合能力。批量集采对成本与供货连续性敏感。','建议以多制式模组组合切入智慧城市集采，突出成本与供货优势，跟踪各地项目公示与集采节奏。','["智慧城市感知终端集采规模扩大","LoRa 与 NB-IoT 路线并行","覆盖路灯、环境、停车等多场景","项目多为政府主导、批量集采"]',24,12,208,9001,'2026-07-06 10:20:00','2026-07-06 10:20:00'),
 (97407,'trend','RedCap 规模商用提速，2026 下半年终端集中放量','多家运营商完成 RedCap 网络就绪，工业与穿戴终端进入集中上市窗口。','第三方市场研究报告','第三方研究机构指出，随着多家运营商完成 RedCap 网络侧升级与商用就绪，2026 下半年 RedCap 终端将进入集中上市窗口，工业网关、视频监控与高端穿戴是首批放量场景，模组需求随之抬升。','RedCap 集中放量意味着中速档位模组需求快速上升，抢先完成认证与量产的厂商更易切入首批标杆项目。我司需确保 RedCap 产品认证节奏与供货能力同步跟上市场窗口。','建议产品线确认 RedCap 产品认证与量产排期，销售侧提前锁定工业网关、监控类目标客户的早期机会。','["多家运营商完成 RedCap 网络就绪与商用","工业网关、监控、穿戴为首批放量场景","RedCap 填补 Cat.4 与 5G 之间的速率/成本档位","网络覆盖成熟度仍是规模落地关键变量"]',52,29,468,9001,'2026-01-20 10:00:00','2026-01-20 10:00:00'),
 (97408,'industrial','工业 AMR/AGV 无线通信向 5G+RedCap 迁移','仓储物流 AMR 规模扩张，对低时延高可靠无线通信与漫游能力需求提升。','工业互联网联盟简报','仓储与制造场景的 AMR/AGV 部署规模持续扩张，对低时延、高可靠无线通信与快速漫游切换的需求提升，通信方案正从 Wi-Fi 向 5G 专网与 RedCap 迁移，带动工业级模组需求。','AMR/AGV 场景对无线可靠性与漫游切换要求苛刻，5G 专网与 RedCap 是主流演进方向，具备工业积累与定制能力的厂商更易切入。需关注头部物流与制造客户的技术验证节奏。','建议针对仓储物流与制造头部客户提供 5G/RedCap 移动场景方案，突出可靠性、漫游与本地 FAE 支持能力。','["仓储物流 AMR/AGV 部署规模扩张","通信方案从 Wi-Fi 向 5G/RedCap 迁移","低时延、高可靠、快速漫游成硬指标","对工业级模组的定制与本地支持要求高"]',30,17,251,9001,'2026-02-25 09:20:00','2026-02-25 09:20:00'),
 (97409,'automotive','车载 T-Box 向 5G+高精定位一体化演进','新车型 T-Box 集成 5G 与高精定位需求上升，模组与定位一体化方案受青睐。','汽车电子行业周报','行业周报显示，新车型 T-Box 对 5G 通信与高精定位（GNSS+RTK/DR）一体化集成的需求上升，车厂倾向选择通信与定位融合的方案以降低集成复杂度与 BOM 成本，带动车规模组结构升级。','通信+定位一体化正成为车载 T-Box 新趋势，具备 5G 模组与高精定位（如 LC29H 系列）组合能力的厂商更具方案竞争力。需跟踪车厂对一体化方案的选型偏好与认证要求。','建议向车厂客户同步 5G+高精定位一体化趋势与选型建议，突出我司通信与定位产品组合及车规认证积累。','["新车型 T-Box 集成 5G + 高精定位需求上升","通信与定位一体化降低集成复杂度","GNSS+RTK/DR 组合满足车道级定位","车规认证与功能安全要求同步抬高"]',41,23,372,9001,'2026-03-30 09:30:00','2026-03-30 09:30:00'),
 (97410,'energy','分布式光伏与逆变器物联化带动通信模组增长','户用与工商业光伏快速增长，逆变器与优化器联网需求拉动工业模组用量。','能源行业协会通讯','分布式光伏（户用与工商业）装机快速增长，逆变器、优化器与储能设备的物联化联网需求随之提升，带动工业级通信模组（Cat.1/Cat.4/NB）在能源领域的稳定增长，尤其看重宽温可靠性与长供货。','光伏物联化为工业模组带来稳定增量，能源场景对可靠性与生命周期要求严苛，利好具备工业级产品与认证积累的厂商。需关注头部逆变器与储能厂商的选型与备货节奏。','建议突出我司工业级模组的宽温、可靠性与长供货能力，对接头部逆变器/储能厂商提供能源场景选型方案。','["分布式光伏装机快速增长","逆变器/优化器/储能联网需求提升","Cat.1、Cat.4、NB 为主力选型","宽温、可靠性与长供货是关键要求"]',34,19,289,9001,'2026-04-28 11:15:00','2026-04-28 11:15:00'),
 (97411,'policy','卫星物联网 NTN 频谱与试点政策落地','监管推进 NTN 频谱与试点管理，天地一体物联网进入早期规模验证阶段。','公开政策信息汇总','监管部门陆续推进卫星物联网 NTN（非地面网络）频谱规划与试点管理办法落地，天地一体物联网进入早期规模验证阶段，偏远、海洋与应急场景的广域连接需求被激活，带动支持 NTN 的模组关注度上升。','NTN 政策明朗为卫星物联网早期布局提供窗口，但终端成本与商业模式仍待成熟。提前布局 NTN 能力与认证的厂商有望在应急、海洋等场景抢占先机。','建议产品线跟踪 NTN 标准与频谱进展，评估 NTN 产品布局，销售侧关注应急、海洋监测等早期示范项目机会。','["NTN 频谱规划与试点管理办法落地","偏远、海洋、应急为核心目标场景","支持 NTN 的模组关注度上升","商业模式与终端成本仍是规模化门槛"]',38,21,314,9001,'2026-05-22 14:40:00','2026-05-22 14:40:00'),
 (97412,'smartcity','智慧水务表计集采扩大，NB-IoT 仍为主力路线','多地推进智慧水务改造，智能水表与管网监测集采规模持续扩大。','智慧城市项目公示','多地持续推进智慧水务改造，智能水表、管网压力与流量监测终端集采规模扩大，NB-IoT 凭借深度覆盖与低功耗仍是主力技术路线，Cat.1 用于对回传实时性要求更高的管网节点。','智慧水务集采规模大、回款相对稳定，NB-IoT 与 Cat.1 组合是主流选型。批量集采对成本与供货连续性敏感，需提前对接水司集成商与终端厂商。','建议以 NB/Cat.1 模组组合切入智慧水务集采，突出成本与供货优势，跟踪各地水务项目公示与集采节奏。','["智慧水务改造与集采规模扩大","智能水表、管网监测为主要终端","NB-IoT 深度覆盖低功耗仍为主力","项目多为政府/水司主导、批量集采"]',27,14,223,9001,'2026-06-18 10:10:00','2026-06-18 10:10:00');
