-- =============================================================================
-- 销售商机互助平台 · 吐槽墙 + 情报中心 演示种子数据（Phase 6）
-- 依赖：先执行 schema.sql（feedback / competitor_intel / industry_intel 三表）。
-- 来源：前端 apis/feedback/mocks/feedback.json、apis/intel/mocks/intel.json 逐行转录。
-- id 段：feedback 97201~，competitor_intel 97301~，industry_intel 97401~（dev 固定 id 便于复现）。
-- 幂等：按固定 id 段先删后插，可重复执行。
-- 说明：submitter_id 置 NULL（mock 提交人多为演示姓名，非本地 sys_user）；submitter_name 保留快照。
--       create_by 统一 9001（运营管理员，仅反滥用留痕，接口不出）。
-- =============================================================================
USE `sales_lead_hub_server`;
SET NAMES utf8mb4;

-- ---------- 吐槽墙（feedback，13 条） ----------
DELETE FROM `feedback` WHERE `id` BETWEEN 97201 AND 97299;

-- ---------- 竞品情报（competitor_intel，14 条） ----------
DELETE FROM `competitor_intel` WHERE `id` BETWEEN 97301 AND 97399;

-- ---------- 行业情报（industry_intel，12 条） ----------
DELETE FROM `industry_intel` WHERE `id` BETWEEN 97401 AND 97499;
